import toast from "react-hot-toast";

export const showLogoutToast = () => {
  toast.success("Successfully logged out 👋", {
    duration: 2000,
    style: {
      background: "#0f172a",
      color: "#ffffff",
      borderRadius: "12px",
      padding: "14px 16px",
      fontSize: "14px",
    },
    icon: "🚀",
  });
};
